// Reads SF_BASE_URL from the Configuration node.
// Builds OData filter URLs for the last 24 hours.

const config = $('Set Config Variables').first().json;
const SF_BASE_URL = config.SF_BASE_URL;

const now       = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);

// SF OData V2 expects datetime'YYYY-MM-DDTHH:mm:ss' (no ms, no Z)
const fmt = (d) => d.toISOString().slice(0, 19);
const fromDate = fmt(yesterday);
const toDate   = fmt(now);

const displayDate = now.toLocaleDateString('de-DE', {
  day: '2-digit', month: '2-digit', year: 'numeric'
});

// ---- Hires: EmpJob startDate in time window ----
const hiresUrl =
  SF_BASE_URL + '/EmpJob' +
  "?$filter=startDate ge datetime'" + fromDate + "' and startDate lt datetime'" + toDate + "'" +
  '&$select=userId,startDate,position,department,location,managerId' +
  '&$expand=userNav' +
  '&$top=200&$format=json';

// ---- Terminations: EmpEmployment endDate in time window ----
const terminationsUrl =
  SF_BASE_URL + '/EmpEmployment' +
  "?$filter=endDate ge datetime'" + fromDate + "' and endDate lt datetime'" + toDate + "'" +
  '&$select=userId,startDate,endDate' +
  '&$expand=userNav' +
  '&$top=200&$format=json';

// ---- Internal moves: EmpJob lastModifiedDateTime in window, not a new hire ----
const movesUrl =
  SF_BASE_URL + '/EmpJob' +
  "?$filter=lastModifiedDateTime ge datetime'" + fromDate + "' and startDate lt datetime'" + fromDate + "'" +
  '&$select=userId,startDate,position,department,location,managerId,lastModifiedDateTime' +
  '&$expand=userNav' +
  '&$top=200&$format=json';

// ---- Address changes: PerAddressDEFLT ----
// Uses personIdExternal (not userId) + personNav for name resolution
const addressesUrl =
  SF_BASE_URL + '/PerAddressDEFLT' +
  "?$filter=lastModifiedDateTime ge datetime'" + fromDate + "'" +
  '&$select=personIdExternal,city,country,lastModifiedDateTime' +
  '&$expand=personNav' +
  '&$top=200&$format=json';

return [{
  json: {
    fromDate,
    toDate,
    displayDate,
    SF_BASE_URL,
    hiresUrl,
    terminationsUrl,
    movesUrl,
    addressesUrl
  }
}];

// Aggregates results from all 4 SF queries.
// Note: PerAddressDEFLT uses personIdExternal + personNav
//       (not userId/userNav like EmpJob/EmpEmployment).

const dateInfo = $('Calculate Date Range').first().json;

function safeResults(nodeName) {
  try {
    const data = $(nodeName).first().json;
    if (data && data.error) {
      const msg = (data.error.message || data.error.description || JSON.stringify(data.error));
      return { data: [], error: nodeName + ': ' + msg };
    }
    return { data: (data.d && data.d.results) || [], error: null };
  } catch (e) {
    return { data: [], error: nodeName + ': ' + e.message };
  }
}

const hiresResult = safeResults('Fetch Hires');
const termsResult = safeResults('Fetch Terminations');
const movesResult = safeResults('Fetch Moves');
const addrResult  = safeResults('Fetch Addresses');

function nameFromUserNav(r) {
  if (r && r.userNav) {
    return ((r.userNav.firstName || '') + ' ' + (r.userNav.lastName || '')).trim() || r.userId;
  }
  return r && r.userId ? r.userId : '(unknown)';
}

function nameFromPersonNav(r) {
  if (r && r.personNav) {
    const nav = r.personNav;
    if (nav.firstName || nav.lastName) {
      return ((nav.firstName || '') + ' ' + (nav.lastName || '')).trim();
    }
  }
  return r && r.personIdExternal ? r.personIdExternal : '(unknown)';
}

const hires = hiresResult.data.map(function(r) {
  return {
    name:       nameFromUserNav(r),
    empId:      (r.userNav && r.userNav.empId) || r.userId || '—',
    startDate:  r.startDate  || '—',
    position:   r.position   || '—',
    department: r.department || '—',
    location:   r.location   || '—'
  };
});

const terminations = termsResult.data.map(function(r) {
  return {
    name:            nameFromUserNav(r),
    empId:           (r.userNav && r.userNav.empId) || r.userId || '—',
    terminationDate: r.endDate   || '—',
    startDate:       r.startDate || '—'
  };
});

const hireUserIds = new Set(hiresResult.data.map(function(r) { return r.userId; }));
const internalMoves = movesResult.data
  .filter(function(r) { return !hireUserIds.has(r.userId); })
  .map(function(r) {
    return {
      name:          nameFromUserNav(r),
      empId:         (r.userNav && r.userNav.empId) || r.userId || '—',
      newPosition:   r.position   || '—',
      newDepartment: r.department || '—',
      newLocation:   r.location   || '—',
      newManager:    r.managerId  || '—',
      changeDate:    r.lastModifiedDateTime || '—'
    };
  });

const addressChanges = addrResult.data.map(function(r) {
  return {
    name:       nameFromPersonNav(r),
    empId:      r.personIdExternal || '—',
    city:       r.city    || '—',
    country:    r.country || '—',
    changeDate: r.lastModifiedDateTime || '—'
  };
});

const errors = [
  hiresResult.error,
  termsResult.error,
  movesResult.error,
  addrResult.error
].filter(Boolean);

const criticalError = (errors.length === 4);
const totalChanges  = hires.length + terminations.length + internalMoves.length + addressChanges.length;

return [{
  json: {
    displayDate:   dateInfo.displayDate,
    fromDate:      dateInfo.fromDate,
    toDate:        dateInfo.toDate,
    criticalError,
    errors,
    counts: {
      hires:          hires.length,
      terminations:   terminations.length,
      internalMoves:  internalMoves.length,
      addressChanges: addressChanges.length
    },
    totalChanges,
    hires,
    terminations,
    internalMoves,
    addressChanges
  }
}];

// Builds system and user prompts for the OpenAI call.
// DIGEST_LANGUAGE controls the response language (e.g. German, English, French).

const d    = $input.first().json;
const lang = $('Set Config Variables').first().json.DIGEST_LANGUAGE || 'German';

const systemPrompt =
  'You are an HR assistant summarizing daily people changes in neutral, professional HR language. ' +
  'Respond in ' + lang + '. Maximum 400 words. Use clear bullet points for each person.';

const errorNote = (d.errors && d.errors.length > 0)
  ? ('\n\nNOTE: Data could not be retrieved for the following categories (please verify manually):\n- ' + d.errors.join('\n- '))
  : '';

const changeData = JSON.stringify({
  hires:          d.hires,
  terminations:   d.terminations,
  internalMoves:  d.internalMoves,
  addressChanges: d.addressChanges
}, null, 2);

const userPrompt =
  'Create a Daily People-Changes Digest for ' + d.displayDate + '.\n\n' +
  'Use exactly this structure:\n' +
  '# Daily People-Changes Digest – ' + d.displayDate + '\n\n' +
  '## Hires (' + d.counts.hires + ')\n' +
  '## Terminations (' + d.counts.terminations + ')\n' +
  '## Internal Moves (' + d.counts.internalMoves + ')\n' +
  '## Address Changes (' + d.counts.addressChanges + ')\n\n' +
  'Rules:\n' +
  '- Empty categories: write "No changes."\n' +
  '- Last line: "Total: ' + d.totalChanges + ' change(s) today."\n' +
  '- Show employee ID (empId) in parentheses after each name.\n\n' +
  'Data:\n' + changeData + errorNote;

return [{ json: { ...d, systemPrompt, userPrompt } }];

// Reads EMAIL_TO from the Configuration node.

const EMAIL_TO  = $('Set Config Variables').first().json.EMAIL_TO;
const aiJson    = $input.first().json;
const promptCtx = $('Create AI Prompt').first().json;

const digestText =
  (aiJson.choices && aiJson.choices[0] && aiJson.choices[0].message && aiJson.choices[0].message.content)
  || '[ERROR: No AI response received]';

return [{
  json: {
    to:          EMAIL_TO,
    subject:     'Daily People-Changes Digest - ' + promptCtx.displayDate,
    text:        digestText,
    displayDate: promptCtx.displayDate,
    counts:      promptCtx.counts,
    totalChanges: promptCtx.totalChanges
  }
}];

const d = $('Draft Digest Email').first().json;
const c = d.counts || {};
const msg =
  '[SFEC Digest ' + d.displayDate + '] ' +
  'Hires: '   + (c.hires          || 0) + ' | ' +
  'Terms: '   + (c.terminations   || 0) + ' | ' +
  'Moves: '   + (c.internalMoves  || 0) + ' | ' +
  'Addr: '    + (c.addressChanges || 0) + ' | ' +
  'Total: '   + (d.totalChanges   || 0);
console.log(msg);
return [{ json: { status: 'digest_sent', date: d.displayDate, counts: c, totalChanges: d.totalChanges, log: msg } }];

// No changes detected — no digest sent.
// To send a "no changes" notification, replace this node with an email node.
const d = $input.first().json;
const msg = '[SFEC Digest ' + d.displayDate + '] No people changes today — digest skipped.';
console.log(msg);
return [{ json: { status: 'no_changes', date: d.displayDate, log: msg } }];

// Reads EMAIL_TO from the Configuration node.
// Triggered when all 4 SF API calls fail simultaneously.

const EMAIL_TO = $('Set Config Variables').first().json.EMAIL_TO;
const d        = $input.first().json;
const errorList = (d.errors || ['Unknown error']).join('\n- ');

const text =
  'The SFEC Daily People-Changes Digest could NOT be created.\n\n' +
  'Date:      ' + d.displayDate + '\n' +
  'Timeframe: ' + d.fromDate + '  →  ' + d.toDate + '\n\n' +
  'Errors:\n- ' + errorList + '\n\n' +
  'Please check the SuccessFactors connection and credentials.\n\n' +
  '— n8n SFEC Digest Automation';

return [{
  json: {
    to:      EMAIL_TO,
    subject: '[ERROR] SFEC Daily Digest - ' + d.displayDate,
    text:    text
  }
}];
